{
    "phone_number": "{{customer_phone}}",
    "channel": "whatsapp",
    "message_type": "interactive",
    "whatsapp_phone_number_id": "{{whatsapp_phone_number_id}}",
    "interactive": {
        "type": "cta_url",
        "body": {
            "text": "Check out our latest products!"
        },
        "footer": {
            "text": "Tap the button below"
        },
        "action": {
            "name": "cta_url",
            "parameters": {
                "display_text": "Visit Store",
                "url": "https://example.com/store"
            }
        }
    }
}

{
    "phone_number": "{{customer_phone}}",
    "channel": "whatsapp",
    "message_type": "interactive",
    "whatsapp_phone_number_id": "{{whatsapp_phone_number_id}}",
    "interactive": {
        "type": "button",
        "body": {
            "text": "How would you rate our service?"
        },
        "footer": {
            "text": "Your feedback helps us improve"
        },
        "action": {
            "buttons": [
                {
                    "type": "reply",
                    "reply": { "id": "rating_good", "title": "Good" }
                },
                {
                    "type": "reply",
                    "reply": { "id": "rating_ok", "title": "Okay" }
                },
                {
                    "type": "reply",
                    "reply": { "id": "rating_bad", "title": "Bad" }
                }
            ]
        }
    }
}

{
    "phone_number": "{{customer_phone}}",
    "channel": "whatsapp",
    "message_type": "interactive",
    "whatsapp_phone_number_id": "{{whatsapp_phone_number_id}}",
    "interactive": {
        "type": "list",
        "body": {
            "text": "Please select a service from our menu"
        },
        "header": {
            "type": "text",
            "text": "Our Services"
        },
        "footer": {
            "text": "Tap the button to see options"
        },
        "action": {
            "button": "View Menu",
            "sections": [
                {
                    "title": "Hair Services",
                    "rows": [
                        {
                            "id": "haircut",
                            "title": "Haircut",
                            "description": "Basic haircut service"
                        },
                        {
                            "id": "hair_coloring",
                            "title": "Hair Coloring",
                            "description": "Full hair coloring service"
                        }
                    ]
                },
                {
                    "title": "Spa Services",
                    "rows": [
                        {
                            "id": "massage",
                            "title": "Massage",
                            "description": "60-minute relaxing massage"
                        },
                        {
                            "id": "facial",
                            "title": "Facial Treatment",
                            "description": "Deep cleansing facial"
                        }
                    ]
                }
            ]
        }
    }
}
